package net.momcorp.micro;


// Packages and classes to import of spring boot.
import org.springframework.boot.SpringApplication;
import org.springframework.boot.autoconfigure.SpringBootApplication;
import org.springframework.cache.annotation.EnableCaching;
import org.springframework.context.annotation.Import;

// Packages and classes to import of lombok.
import lombok.extern.slf4j.Slf4j;

// Packages and classes to import of momcorp.
import net.momcorp.commons.services.config.MomcorpServiceConfig;
import net.momcorp.commons.repository.config.MomcorpRepositoryConfig;
import net.momcorp.commons.components.config.MomcorpBaseConfig;
import net.momcorp.commons.components.config.MomcorpAOPConfig;


/**
 *  <p>The {@code Application} class is the entry point for the Spring Boot application.</p>
 *
 *  <p>It bootstraps the Spring context and launches the application.</p>
 *
 *  <p>This class is typically run using {@code java -jar app.jar} or via Spring Boot's Maven/Gradle plugins.</p>
 *
 *  @author Raul Pena (raul.pena@gmail.com)
 *  @version 1.0.0
 *  @since jdk 21
 *  @see Slf4j
 *  @see Import
 *  @see MomcorpBaseConfig
 *  @see MomcorpAOPConfig
 *  @see MomcorpRepositoryConfig
 *  @see MomcorpServiceConfig
 *  @see org.springframework.boot.SpringApplication
 *  @see org.springframework.boot.autoconfigure.SpringBootApplication
 */
@Import({
		MomcorpBaseConfig.class,
		MomcorpAOPConfig.class,
		MomcorpRepositoryConfig.class,
		MomcorpServiceConfig.class
})
@Slf4j
@SpringBootApplication
@EnableCaching
public class Application {


    // Constructor declarations.
    /**
     *  Default constructor.
     */
    public Application() {

        // Call super class.
        super();
    }


	// Public class methods declarations.
	/**
	 * The main method serves as the entry point for the Spring Boot application.
	 *
	 * @param args command-line arguments passed to the application
	 */
	public static void main(String[] args) {

		log.info("Momcorp :: Starting application...");
		SpringApplication.run(Application.class, args);
		log.info("Momcorp :: Application started successfully.");
	}
}

