package net.momcorp.micro.commons.controller;


// Packages and classes to import of JAKARTA EE.
import jakarta.annotation.PostConstruct;
import jakarta.validation.Valid;

// Packages and classes to import of springframework. 6.x
import org.springframework.http.HttpHeaders;
import org.springframework.http.MediaType;
import org.springframework.http.ResponseEntity;
import org.springframework.web.bind.annotation.*;

// Packages and classes to import of open api.
import io.swagger.v3.oas.annotations.Operation;
import io.swagger.v3.oas.annotations.responses.ApiResponse;
import io.swagger.v3.oas.annotations.responses.ApiResponses;

// Packages and classes to import of logbook.
import lombok.extern.slf4j.Slf4j;

// Packages and classes to import of momcorp api.
import net.momcorp.micro.commons.utils.WebUtils;
import net.momcorp.commons.dto.core.response.NaturalPersonResponse;
import net.momcorp.commons.components.MomcorpHeadersEnum;
import net.momcorp.commons.components.MomcorpRequestContextHolder;
import net.momcorp.commons.dto.core.NaturalPersonDto;
import net.momcorp.commons.services.core.INaturalPersonService;
import net.momcorp.commons.components.web.BaseWebController;
import net.momcorp.commons.components.base.ApplicationProperties;
import org.springframework.web.util.UriComponentsBuilder;


/**
 *  CountryController provides endpoints to retrieve meta information about the API.
 *  It is a REST controller that handles requests related to country API.
 *
 *  <p>This controller extends BaseWebController to inherit common web functionalities and publish info about the country API.
 *
 *  @author Raul Pena (raul.pena@gmail.com)
 *  @version 1.0.0
 *  @since jdk 21
 *  @since 08/20/2025
 *
 *  @see Slf4j
 *  @see RestController
 *  @see RequestMapping
 *  @see BaseWebController
 */
@Slf4j
@RestController
@RequestMapping("natural-persons")
public class NaturalPersonController extends BaseWebController {


    // Private instance variables declarations.
    // The natural person service instance that provides natural-persons-related functionalities.
    private final INaturalPersonService<NaturalPersonDto, NaturalPersonResponse, String> naturalPersonService;


    // Public constructor declarations.
    /**
     *
     *  <p>Constructor for CountryController that initializes the controller with application properties.
     *
     *  @param applicationProperties the application properties containing configuration values.
     *  @param naturalPersonService the natural person service instance that provides natural-person--related functionalities.
     *
     *  @see ApplicationProperties
     * */
    public NaturalPersonController(ApplicationProperties applicationProperties, INaturalPersonService<NaturalPersonDto, NaturalPersonResponse, String> naturalPersonService) {

        // Call super class.
        super(applicationProperties);

        // Initialize the internal services.
        this.naturalPersonService = naturalPersonService;
    }


    // Public instance methods declarations
    /**
     *  <p>This method is called after the controller is constructed and
     *
     * @see PostConstruct
     * */
    @PostConstruct
    public void init() {

        log.info("Momcorp :: NaturalPersonController has been loaded and initialized!");
    }


    /**
     *
     *  <p>Method to create a new natural person.
     *
     *  @param naturalPersonDto the natural person data transfer object containing the details of the natural person to be created.
     *  @param uriBuilder the UriComponentsBuilder to build the location URI of the created resource.
     *
     *  @return ResponseEntity containing a BaseResponseDto with the created natural person details and HTTP status code.
     *
     *  @see PostMapping
     *  @see Operation
     *  @see ApiResponse
     *  @see ApiResponses
     *  @see NaturalPersonDto
     *  @see UriComponentsBuilder
     *  @see RequestBody
     *  @see Valid
     *  @see ResponseEntity
     * */
    @PostMapping(
            value = "",
            consumes = MediaType.APPLICATION_JSON_VALUE,
            produces = MediaType.APPLICATION_JSON_VALUE
    )
    @Operation(
            summary = "Create a new natural person",
            description = "Creates a new natural person and returns the created entity."
    )
    @ApiResponses({
            @ApiResponse(responseCode = "201", description = "Natural person created successfully"),
            @ApiResponse(responseCode = "400", description = "Invalid input data"),
            @ApiResponse(responseCode = "500", description = "Internal server error")
    })
    public ResponseEntity<Void> createNaturalPerson(@Valid @RequestBody NaturalPersonDto naturalPersonDto, UriComponentsBuilder uriBuilder) {

        // Transaction id.
        final String transactionId = MomcorpRequestContextHolder.get().getOrDefault(MomcorpHeadersEnum.X_MOMCORP_TRACERID, "N/A");

        // Log the request.
        log.debug("Momcorp[{}] :: Creating new natural person from DTO {}", transactionId, naturalPersonDto);
        final var naturalPersonId = naturalPersonService.create(naturalPersonDto);

        log.debug("Momcorp[{}] :: New natural person created {}", transactionId, naturalPersonId);
        HttpHeaders headers = new HttpHeaders();
        headers.setLocation(uriBuilder.path("/natural-persons/{id}").buildAndExpand(naturalPersonId).toUri());

        // Returning response entity.
        return ResponseEntity.noContent().headers(headers).build();
    }


    /**
     *
     *  <p>Method to find a natural person by id.
     *
     *  @param id the identifier of the natural person to be retrieved.
     *
     *  @return ResponseEntity containing a NaturalPersonResponse with the natural person details and HTTP status code.
     *
     *  @see GetMapping
     *  @see Operation
     *  @see ApiResponse
     *  @see ApiResponses
     *  @see NaturalPersonResponse
     *  @see PathVariable
     * */
    @GetMapping(
            value = "/{id}",
            produces = MediaType.APPLICATION_JSON_VALUE
    )
    @Operation(
            summary = "Get natural person by id",
            description = "Retrieves a natural person by its identifier."
    )
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Natural person found"),
            @ApiResponse(responseCode = "404", description = "Natural person not found"),
            @ApiResponse(responseCode = "500", description = "Internal server error")
    })
    public ResponseEntity<NaturalPersonResponse> findNaturalPersonById(@PathVariable("id") String id) {

        final String transactionId = MomcorpRequestContextHolder.get().getOrDefault(MomcorpHeadersEnum.X_MOMCORP_TRACERID, "N/A");
        log.info("Momcorp[{}] :: Retrieving natural person by id {}", transactionId, id);

        log.debug("Momcorp[{}] :: Looking for natural person by id {}", transactionId, id);
        final var naturalPerson = naturalPersonService.findById(id);

        if (naturalPerson == null) {
            log.warn("Momcorp[{}] :: Natural person with id {} not found", transactionId, id);
            return ResponseEntity.notFound().build();
        }

        log.debug("Momcorp[{}] :: Natural person with id {} retrieved", transactionId, id);
        WebUtils.fillOutResponseFields(naturalPerson, transactionId, "Natural person retrieved successfully");
        return ResponseEntity.ok(naturalPerson);
    }


    /**
     *
     *  <p>Method to delete a natural person by id.
     *
     *  @param id the identifier of the natural person to be retrieved.
     *
     *  @return Nothing.
     *
     *  @see DeleteMapping
     *  @see Operation
     *  @see ApiResponse
     *  @see ApiResponses
     *  @see NaturalPersonResponse
     *  @see PathVariable
     * */
    @DeleteMapping(
            value = "/{id}",
            produces = MediaType.APPLICATION_JSON_VALUE
    )
    @Operation(
            summary = "Delete natural person by id",
            description = "Deletes a natural person by its identifier."
    )
    @ApiResponses({
            @ApiResponse(responseCode = "204", description = "Natural person deleted successfully"),
            @ApiResponse(responseCode = "404", description = "Natural person not found"),
            @ApiResponse(responseCode = "500", description = "Internal server error")
    })
    public ResponseEntity<Void> deleteNaturalPersonById(@PathVariable("id") String id) {

        final String transactionId = MomcorpRequestContextHolder.get().getOrDefault(MomcorpHeadersEnum.X_MOMCORP_TRACERID, "N/A");
        log.info("Momcorp[{}] :: Deleting natural person by id {}", transactionId, id);

        naturalPersonService.delete(id);

        log.debug("Momcorp[{}] :: Natural person with id {} deleted", transactionId, id);
        return ResponseEntity.noContent().build();
    }


    /**
     *
     *  <p>Method to update a natural person.
     *
     *  @param id the identifier of the natural person to be updated.
     *  @param naturalPersonDto the natural person data transfer object containing the details of the natural person to be created.
     *
     *
     *  @return ResponseEntity containing a BaseResponseDto with the updated natural person details and HTTP status code.
     *
     *  @see PutMapping
     *  @see Operation
     *  @see ApiResponse
     *  @see ApiResponses
     *  @see NaturalPersonDto
     *  @see PathVariable
     *  @see RequestBody
     *  @see Valid
     *  @see ResponseEntity
     * */
    @PutMapping(
            value = "/{id}",
            consumes = MediaType.APPLICATION_JSON_VALUE,
            produces = MediaType.APPLICATION_JSON_VALUE
    )
    @Operation(
            summary = "Update natural person by id",
            description = "Updates an existing natural person by its identifier."
    )
    @ApiResponses({
            @ApiResponse(responseCode = "200", description = "Natural person updated successfully"),
            @ApiResponse(responseCode = "400", description = "Invalid input data"),
            @ApiResponse(responseCode = "404", description = "Natural person not found"),
            @ApiResponse(responseCode = "500", description = "Internal server error")
    })
    public ResponseEntity<NaturalPersonResponse> updateNaturalPersonById(@PathVariable("id") String id,
                                                                         @Valid @RequestBody NaturalPersonDto naturalPersonDto) {

        final String transactionId = MomcorpRequestContextHolder.get().getOrDefault(MomcorpHeadersEnum.X_MOMCORP_TRACERID, "N/A");
        log.info("Momcorp[{}] :: Updating natural person by id {}", transactionId, id);

        if (!id.equals(naturalPersonDto.getId())) {

            log.warn("Momcorp[{}] :: Natural person with id {} is incorrect. [{}][{}]", transactionId, id, id, naturalPersonDto.getId());
            return ResponseEntity.badRequest().build();
        }

        // Perform update (service method expected to accept id and dto and return the updated response)
        log.debug("Momcorp[{}] :: Updating natural person by id {} from dto {}", transactionId, id, naturalPersonDto);
        naturalPersonDto.setId(id);
        final var updated = naturalPersonService.update(naturalPersonDto);

        log.debug("Momcorp[{}] :: Natural person with id {} updated.", transactionId, id);
        WebUtils.fillOutResponseFields(updated, transactionId, "Natural person updated successfully");
        return ResponseEntity.ok(updated);
    }
}
